export const getLoginUrl = () => {
	return `/api/auth/login`;
};

/**
 * @summary Log in with local admin credentials
 */
export const login = async (
	loginRequest: LoginRequest,
	options?: RequestInit
): Promise<SessionResponse> => {
	const res = await fetch(getLoginUrl(), {
		...options,
		method: 'POST',
		headers: { 'Content-Type': 'application/json', ...options?.headers },
		body: JSON.stringify(loginRequest)
	});

	const body = [204, 205, 304].includes(res.status) ? null : await res.text();

	const data: SessionResponse = body ? JSON.parse(body) : {};
	return data;
};

export const getLoginQueryKey = (loginRequest?: LoginRequest) => {
	return ['POST', `/api/auth/login`, loginRequest] as const;
};

export const getLoginQueryOptions = <
	TData = Awaited<ReturnType<typeof login>>,
	TError = BadRequestResponse | UnauthorizedResponse | RateLimitedResponse
>(
	loginRequest: LoginRequest,
	options?: {
		query?: Partial<CreateQueryOptions<Awaited<ReturnType<typeof login>>, TError, TData>>;
		fetch?: RequestInit;
	}
) => {
	const { query: queryOptions, fetch: fetchOptions } = options ?? {};

	const queryKey = queryOptions?.queryKey ?? getLoginQueryKey(loginRequest);

	const queryFn: QueryFunction<Awaited<ReturnType<typeof login>>> = ({ signal }) =>
		login(loginRequest, { signal, ...fetchOptions });

	return { queryKey, queryFn, ...queryOptions } as CreateQueryOptions<
		Awaited<ReturnType<typeof login>>,
		TError,
		TData
	> & { queryKey: DataTag<QueryKey, TData, TError> };
};

